// ============================================================
// IMPORTAR HISTORIAL STRAVA → PostgreSQL
// Procesa hasta 100 actividades tipo Run
// ============================================================
const actividades = $input.all().map(i => i.json);

const runs = actividades.filter(a => a.type === 'Run');

if (runs.length === 0) {
  return [{ json: { query: 'SELECT 1', total: 0, message: 'No hay actividades tipo Run en esta página' } }];
}

const inserts = runs.map(a => {
  const durationMin = (a.moving_time || 0) / 60;
  const distanceKm = (a.distance || 0) / 1000;
  const paceSecKm = distanceKm > 0 ? (a.moving_time / distanceKm) : 0;
  const paceMin = Math.floor(paceSecKm / 60);
  const paceSec = Math.round(paceSecKm % 60);
  const pace = `${paceMin}:${String(paceSec).padStart(2,'0')} min/km`;
  const avgHR = a.average_heartrate || 0;
  const maxHR = a.max_heartrate || 0;
  const hrMax = [FC_MAX];
  const hrRest = [FC_REPOSO];
  const hrRatio = avgHR > 0 ? Math.max(0, Math.min(1.2, (avgHR - hrRest) / (hrMax - hrRest))) : 0;
  const trimp = avgHR > 0
    ? Math.round(durationMin * hrRatio * 0.64 * Math.exp(1.92 * hrRatio))
    : Math.round(durationMin * 1.1);
  const intensityPct = avgHR > 0 ? Math.round((avgHR / hrMax) * 100) : 0;
  let zone = 'Sin FC';
  if (intensityPct > 0 && intensityPct < 70) zone = 'Z2 aeróbico';
  else if (intensityPct < 80) zone = 'Z3 umbral aeróbico';
  else if (intensityPct < 90) zone = 'Z4 umbral anaeróbico';
  else if (intensityPct >= 90) zone = 'Z5 VO2/anaeróbico';
  const lapsCount = a.laps_count || 0;
  const roundLike = lapsCount >= 5;
  let sessionType = 'aeróbico';
  if (intensityPct >= 90) sessionType = 'anaeróbico';
  else if (roundLike && intensityPct >= 82) sessionType = 'específico de combate';
  const nombre = (a.name || 'Run').replace(/'/g, "''");
  const fecha = a.start_date_local || a.start_date;
  const elevacion = a.total_elevation_gain || 0;

  return `(${a.id}, '${fecha}', '${nombre}', ${distanceKm.toFixed(2)}, ${durationMin.toFixed(1)}, '${pace}', ${Math.round(paceSecKm)}, ${avgHR}, ${maxHR}, ${trimp}, ${intensityPct}, '${zone}', 0, ${roundLike}, '${sessionType}', ${elevacion})`;
});

const query = `INSERT INTO boxing_sessions
(activity_id, fecha, nombre, distancia_km, duracion_min, pace, pace_sec_km, fc_media, fc_max, trimp, intensidad_pct, zona, variabilidad, round_like, session_type, elevacion)
VALUES ${inserts.join(',\n')}
ON CONFLICT (activity_id) DO NOTHING`;

return [{ json: { query, total: runs.length, totalActividades: actividades.length } }];

const resultado = $input.first().json;
const total = resultado.total_importadas || 0;
const primera = resultado.primera_fecha ? new Date(resultado.primera_fecha).toLocaleDateString('es-MX') : 'N/D';
const ultima = resultado.ultima_fecha ? new Date(resultado.ultima_fecha).toLocaleDateString('es-MX') : 'N/D';

const mensaje = `✅ Importación completada

📊 Total sesiones en DB: ${total}
📅 Primera sesión: ${primera}
📅 Última sesión: ${ultima}

${total < 100 ? 'Todas las sesiones importadas.' : '⚠️ Tienes más de 100 sesiones. Cambia page=1 a page=2 en el nodo GET y vuelve a ejecutar.'}`;

return [{ json: { mensaje, total } }];

// ============================================================
// PREPARAR DATOS PARA QUE CLAUDE GENERE EL PLAN
// ============================================================
const rows = $input.all().map(r => r.json);
const now = new Date();
const weekMs = 7 * 24 * 60 * 60 * 1000;

const semanas = [0,1,2,3,4].map(w => ({
  sesiones: rows.filter(s => {
    const d = now - new Date(s.fecha);
    return d >= w * weekMs && d < (w+1) * weekMs;
  })
}));

const semActual  = semanas[0].sesiones;
const semAnterior = semanas[1].sesiones;
const sem3 = semanas[2].sesiones;
const sem4 = semanas[3].sesiones;

const metricas = (ses) => ({
  load:     ses.reduce((a,s) => a + (parseInt(s.trimp)||0), 0),
  km:       Number(ses.reduce((a,s) => a + (parseFloat(s.distancia_km)||0), 0).toFixed(1)),
  sessions: ses.length,
  hiit:     ses.filter(s => (parseInt(s.intensidad_pct)||0) >= 85).length,
  rounds:   ses.filter(s => s.round_like).length,
  avgPace:  ses.length ? Math.round(ses.reduce((a,s) => a + (parseInt(s.pace_sec_km)||0), 0) / ses.length) : 0,
  avgHR:    ses.filter(s => s.fc_media > 0).length
              ? Math.round(ses.filter(s => s.fc_media > 0).reduce((a,s) => a + s.fc_media, 0) / ses.filter(s => s.fc_media > 0).length)
              : 0
});

const mA = metricas(semActual);
const mP = metricas(semAnterior);
const m3 = metricas(sem3);
const m4 = metricas(sem4);

const tendLoad = mA.load > mP.load ? 'SUBIENDO' : mA.load < mP.load ? 'BAJANDO' : 'ESTABLE';
const tendPace = mA.avgPace > 0 && mP.avgPace > 0
  ? (mA.avgPace < mP.avgPace ? 'MEJORANDO' : 'BAJANDO')
  : 'SIN DATOS';

const fmtPace = (sec) => sec ? `${Math.floor(sec/60)}:${String(Math.round(sec%60)).padStart(2,'0')} min/km` : 'N/D';

// Récords históricos
const bestPaceSec = rows.filter(s => s.pace_sec_km > 0).reduce((best, s) => (!best || s.pace_sec_km < best) ? s.pace_sec_km : best, null);
const maxTrimp    = rows.reduce((b,s) => s.trimp > b ? s.trimp : b, 0);

// Historial 4 semanas para que Claude vea tendencia
const hist4 = [mA, mP, m3, m4].map((m, i) => `  Semana -${i}: ${m.sessions} ses | ${m.km}km | TRIMP:${m.load} | HIIT:${m.hiit} | Rounds:${m.rounds} | Pace:${fmtPace(m.avgPace)}`);

// Prompt para que Claude genere el plan
const promptPlan = `Eres COACH RAMOS. Entrenador de boxeo con 15 años de experiencia.
Genera el plan de entrenamiento de running para la semana siguiente.

BASE CIENTÍFICA OBLIGATORIA — usa estos autores:
- Eric Banister: modelo TRIMP para cuantificar carga
- Tudor Bompa: periodización ondulante (carga/descarga semanal)
- Vladimir Issurin: periodización en bloques
- Martin Buchheit: HIIT, intervalos 3:1 para sistema glucolítico
- Joel Jamieson: energía específica para deportes de combate
- Ross Enamait: acondicionamiento específico de boxeo
- Yuri Verkhoshansky: sprints y potencia fosfágena
- Arthur Lydiard: base aeróbica antes de intensidad
- Jack Daniels: zonas de FC y VO2max

ATLETA:
- [EDAD] años | [ESTATURA]cm | [DEPORTE] activo
- Running 3x/semana como herramienta, NO como fin
- FC máx: [FC_MAX]bpm | FC reposo: [FC_REPOSO]bpm
- Objetivo: más rounds, más explosividad, mejor recuperación

DATO DE LAS ÚLTIMAS 4 SEMANAS:
${hist4.join('\n')}

TENDENCIAS:
- Carga: ${tendLoad}
- Pace: ${tendPace}
- Récord pace histórico: ${fmtPace(bestPaceSec)}
- Mayor TRIMP registrado: ${maxTrimp}

GENERA exactamente 3 sesiones de running para la semana.
Responde ÚNICAMENTE con un JSON válido, sin texto adicional, sin bloques de código, sin explicaciones:
[
  {
    "dia": "Lunes",
    "tipo": "nombre corto del tipo de sesión",
    "descripcion": "descripción detallada con números exactos: distancia o tiempo, %FC o bpm objetivo, series x tiempo. Menciona brevemente el autor científico que respalda esta sesión.",
    "completado": false,
    "trimp_esperado": número entero
  },
  { ... sesión miércoles ... },
  { ... sesión viernes ... }
]`;

const semanaStr = `${now.getFullYear()}-W${Math.ceil((now.getDate() - now.getDay() + 1) / 7)}`;
// Construir body listo para Claude
const bodyParaClaude = JSON.stringify({
  model: "claude-haiku-4-5-20251001",
  max_tokens: 800,
  messages: [{ role: "user", content: promptPlan }]
});

return [{ json: {
  promptPlan,
  bodyParaClaude,
  mA, mP, tendLoad, tendPace,
  bestPaceSec, maxTrimp,
  semanaStr,
  totalSesiones: rows.length,
  now: now.toISOString()
} }];

// ============================================================
// PROCESAR RESPUESTA DE CLAUDE + CONSTRUIR MENSAJE SEMANAL
// ============================================================
const claudeResp = $input.first().json;
const datosResumen = $('Preparar Datos Resumen').first().json;

const { mA, mP, tendLoad, tendPace, totalSesiones, semanaStr, now: nowStr } = datosResumen;
const now = new Date(nowStr);

// Extraer texto de Claude
let planTextoRaw = '';
if (claudeResp.content && claudeResp.content[0]) {
  planTextoRaw = claudeResp.content[0].text || '';
}

// Parsear JSON del plan
let planSesiones = [];
try {
  // Limpiar por si Claude agregó algo extra
  const jsonMatch = planTextoRaw.match(/\[.*\]/s);
  if (jsonMatch) {
    planSesiones = JSON.parse(jsonMatch[0]);
  } else {
    planSesiones = JSON.parse(planTextoRaw);
  }
} catch(e) {
  // Si Claude no devolvió JSON válido, plan de respaldo
  planSesiones = [
    { dia: 'Lunes', tipo: 'Base aeróbica', descripcion: '30min Z3. Pace 5:30 min/km. Lydiard: base aeróbica primero.', completado: false, trimp_esperado: 50 },
    { dia: 'Miércoles', tipo: 'Rounds simulados', descripcion: '8x(3min 85-90%FC / 1min trote). Buchheit: sistema glucolítico láctico.', completado: false, trimp_esperado: 85 },
    { dia: 'Viernes', tipo: 'Sprints', descripcion: '6x20seg sprint máximo + 90seg recuperación. Verkhoshansky: potencia ATP-PC.', completado: false, trimp_esperado: 40 }
  ];
}

// Asegurar que todas tienen completado: false
planSesiones = planSesiones.map(s => ({ ...s, completado: false }));

// Tendencias con emojis
const tendLoadEmoji = tendLoad === 'SUBIENDO' ? '📈' : tendLoad === 'BAJANDO' ? '📉' : '➡️';
const tendPaceEmoji = tendPace === 'MEJORANDO' ? '📈' : tendPace === 'BAJANDO' ? '📉' : '➡️';

const fmtPace = (sec) => sec ? `${Math.floor(sec/60)}:${String(Math.round(sec%60)).padStart(2,'0')} min/km` : 'N/D';
const avgPaceStr = fmtPace(mA.avgPace);
const comparacion = mP.load > 0
  ? `Esta semana vs anterior: ${mA.load > mP.load ? '+' : ''}${mA.load - mP.load} TRIMP (${mA.load} vs ${mP.load})`
  : 'Primera semana con datos suficientes.';

let nutricion = '';
if (mA.load > 200) nutricion = '🍚 Carga alta → prioriza carbohidratos los días de descanso.';
else if (mA.hiit >= 2) nutricion = '🥩 Sesiones intensas → 20-30g proteína en la hora post-entreno.';
else nutricion = '💧 Semana moderada → hidratación y sueño son tu prioridad.';

const planTexto = planSesiones.map((s, i) =>
  `${i+1}. *${s.dia} — ${s.tipo}*\n   ${s.descripcion}`
).join('\n\n');

const text = `🥊 *COACH RAMOS — RESUMEN SEMANAL*
📅 Domingo ${now.toLocaleDateString('es-MX')}

📊 *Semana completada:*
• Sesiones: ${mA.sessions} | Km: ${mA.km}
• Carga TRIMP: ${mA.load} | Pace medio: ${avgPaceStr}
• Sesiones intensas: ${mA.hiit} | Rounds: ${mA.rounds}
• Carga: ${tendLoadEmoji} ${tendLoad} | Pace: ${tendPaceEmoji} ${tendPace}
• ${comparacion}

📅 *Plan semana nueva (generado por IA):*
${planTexto}

${nutricion}

_📦 ${totalSesiones} sesiones en memoria permanente. 🥊_`;

return [{ json: { text, planSesiones, semanaStr } }];

const a = $input.first().json;
const data = a.body || a;
const athlete = { hrMax: [FC_MAX], hrRest: [FC_REPOSO] };
const durationSec = Number(data.moving_time || 0);
const durationMin = durationSec / 60;
const distanceKm = Number((data.distance || 0) / 1000);
const avgHR = Number(data.average_heartrate || 0);
const maxHR = Number(data.max_heartrate || avgHR || 0);
const elevation = Number(data.total_elevation_gain || 0);
const paceSecKm = distanceKm > 0 ? durationSec / distanceKm : 0;
const pace = `${Math.floor(paceSecKm/60)}:${String(Math.round(paceSecKm%60)).padStart(2,'0')} min/km`;
const hrRatio = avgHR > 0 ? Math.max(0, Math.min(1.2, (avgHR - athlete.hrRest) / (athlete.hrMax - athlete.hrRest))) : 0;
const trimp = avgHR > 0 ? Math.round(durationMin * hrRatio * 0.64 * Math.exp(1.92 * hrRatio)) : Math.round(durationMin * 1.1);
const intensityPct = avgHR > 0 ? Math.round((avgHR / athlete.hrMax) * 100) : 0;
let zone = 'Sin FC';
if (intensityPct > 0 && intensityPct < 70) zone = 'Z2 aeróbico';
else if (intensityPct < 80) zone = 'Z3 umbral aeróbico';
else if (intensityPct < 90) zone = 'Z4 umbral anaeróbico';
else if (intensityPct >= 90) zone = 'Z5 VO2/anaeróbico';
const splits = Array.isArray(data.splits_metric) ? data.splits_metric : [];
const splitPaces = splits.filter(s => s.distance && s.moving_time).map(s => s.moving_time / (s.distance / 1000));
let variability = 0;
if (splitPaces.length > 1) { const avg = splitPaces.reduce((x,y)=>x+y,0)/splitPaces.length; const variance = splitPaces.reduce((acc,p)=>acc+Math.pow(p-avg,2),0)/splitPaces.length; variability = Math.round(Math.sqrt(variance)); }
const laps = Array.isArray(data.laps) ? data.laps.length : 0;
const roundLike = laps >= 5 || variability >= 25;
let sessionType = 'aeróbico';
if (intensityPct >= 90 || (variability > 35 && durationMin < 35)) sessionType = 'anaeróbico';
else if (roundLike && intensityPct >= 82) sessionType = 'específico de combate';
return [{ json: { activityId: data.id || Date.now(), fecha: data.start_date_local || new Date().toISOString(), nombre: data.name || 'Run', distanciaKm: Number(distanceKm.toFixed(2)), duracionMin: Number(durationMin.toFixed(1)), pace, paceSecKm: Math.round(paceSecKm), fcMedia: avgHR, fcMax: maxHR, trimp, intensidadPct: intensityPct, zona: zone, variabilidad: variability, roundLike, sessionType, elevacion: elevation } }];

const a = $('Calcular Métricas Boxeo').first().json;

// Si la actividad no tenia datos de distancia, no procesar
if (a.error || a.distanciaKm === 0) {
  return [{ json: {
    autoMessage: '⚠️ *COACH RAMOS*\n\nTu actividad llegó sin datos completos.\nEspera unos minutos y vuelve a sincronizar en Strava.',
    planActualizado: null
  }}];
}

let planRow = null;
try {
  const planData = $('PG — Leer Plan Post-Run').first()?.json;
  if (planData && planData.sesiones) planRow = planData;
} catch(e) { planRow = null; }

let planInfo = '';
let planActualizado = null;

if (planRow && planRow.sesiones) {
  let sesiones = planRow.sesiones;
  if (typeof sesiones === 'string') sesiones = JSON.parse(sesiones);
  const sesionActual = parseInt(planRow.sesion_actual) || 0;
  const pendiente = sesiones.findIndex((s, i) => i >= sesionActual && !s.completado);
  if (pendiente !== -1) {
    sesiones[pendiente].completado = true;
    sesiones[pendiente].trimpReal = a.trimp;
    sesiones[pendiente].fechaCompletado = a.fecha;
    const nuevaSesionActual = pendiente + 1;
    const planCompletado = sesiones.every(s => s.completado);
    const siguiente = sesiones.find((s, i) => i >= nuevaSesionActual && !s.completado);
    const completadas = sesiones.filter(s => s.completado).length;
    planActualizado = { id: planRow.id, sesiones, sesionActual: nuevaSesionActual, completado: planCompletado };
    if (planCompletado) {
      planInfo = `\n\n🏆 *Plan semanal COMPLETADO* (${completadas}/${sesiones.length})\nEl domingo Claude genera el nuevo plan. 💪`;
    } else if (siguiente) {
      planInfo = `\n\n📋 *Plan: ${completadas}/${sesiones.length} sesiones*\n▶️ *Siguiente:*\n*${siguiente.dia} — ${siguiente.tipo}*\n_${siguiente.descripcion}_`;
    }
  }
}

// Sistema energético
const sistemaTexto = a.sessionType === 'anaeróbico' ? '🔴 Anaeróbico' 
  : a.sessionType === 'específico de combate' ? '🥊 Combate' 
  : '🟢 Aeróbico';

// FC y zona — manejar cuando no hay sensor
const fcTexto = a.fcMedia > 0 ? `${a.fcMedia} bpm` : 'Sin sensor FC';
const zonaTexto = a.fcMedia > 0 ? a.zona : 'Estimada por tiempo';
const trimpTexto = a.fcMedia > 0 ? `${a.trimp}` : `${a.trimp} (estimado)`;

// Pace — manejar cuando es 0
const paceTexto = a.paceSecKm > 0 && a.paceSecKm < 600 ? a.pace : 'N/D';

// Alertas
const alertas = [];
if (a.distanciaKm > 12) alertas.push('⚠️ Volumen alto — adaptaciones de fondista');
if (a.fcMedia > 0 && a.intensidadPct < 70 && a.duracionMin > 30) alertas.push('⚠️ Muy suave y largo — sube intensidad la próxima');

// Nutrición
let nutricion = '';
if (a.trimp > 80) nutricion = '\n🍚 Sesión intensa → carbos en las próximas 2h.';
else if (a.sessionType === 'anaeróbico') nutricion = '\n🥩 Anaeróbico → 20-30g proteína en la hora siguiente.';

const autoMessage = `🥊 *COACH RAMOS — Sesión analizada*

📍 *${a.nombre}*
- ${a.distanciaKm}km en ${a.duracionMin}min
- Pace: ${paceTexto} | FC: ${fcTexto}
- Zona: ${zonaTexto}
- ${sistemaTexto} | TRIMP: ${trimpTexto}

${alertas.length > 0 ? '🚨 ' + alertas.join('\n') + '\n\n' : ''}${nutricion}${planInfo}`;

return [{ json: { autoMessage, planActualizado } }];

const msg = $('Telegram Trigger1').first().json;
const text = msg.message?.text || '';
const chatId = msg.message?.chat?.id;
const userName = msg.message?.from?.first_name || 'atleta';

const historialRows = $('PG — Historial para Chat1').all().map(r => r.json);
const planRow = $('PG — Leer Plan Actual1').first()?.json || null;
const recordsRow = $('PG — Leer Récords').first()?.json || null;

const now = new Date();
const weekMs = 7 * 24 * 60 * 60 * 1000;

const thisWeek = historialRows.filter(s => (now - new Date(s.fecha)) < weekMs);
const lastWeek = historialRows.filter(s => { const d = now - new Date(s.fecha); return d >= weekMs && d < 2*weekMs; });
const weeklyLoad = thisWeek.reduce((a,s) => a + (parseInt(s.trimp)||0), 0);
const lastWeeklyLoad = lastWeek.reduce((a,s) => a + (parseInt(s.trimp)||0), 0);
const hiitThisWeek = thisWeek.filter(s => (parseInt(s.intensidad_pct)||0) >= 85).length;
const kmThisWeek = thisWeek.reduce((a,s) => a + (parseFloat(s.distancia_km)||0), 0).toFixed(1);
const lastSession = historialRows[0] || null;

const bestPaceSec = recordsRow?.best_pace_sec || 0;
const bestPaceStr = bestPaceSec ? `${Math.floor(bestPaceSec/60)}:${String(Math.round(bestPaceSec%60)).padStart(2,'0')} min/km` : 'Sin datos';

const t = text.toLowerCase();
let intencion = 'general';
if (t.includes('qué me toca') || t.includes('hoy qué') || t.includes('toca hoy') || t.includes('qué corro') || t.includes('plan') || t.includes('siguiente')) intencion = 'plan_hoy';
else if (t.includes('cansado') || t.includes('fatigado') || t.includes('pesado') || t.includes('agotado')) intencion = 'fatiga';
else if (t.includes('mejorando') || t.includes('progreso') || t.includes('cómo voy')) intencion = 'progreso';
else if (t.includes('round') || t.includes('aguantar') || t.includes('sparring')) intencion = 'rounds';
else if (t.includes('récord') || t.includes('record')) intencion = 'records';
else if (t.includes('nutrici') || t.includes('comer')) intencion = 'nutricion';
else if (t.includes('historial') || t.includes('cuántas sesiones')) intencion = 'historial';

const last3Trimp = historialRows.slice(0,3).reduce((a,s) => a + (parseInt(s.trimp)||0), 0);
let fatigaEstado = 'controlada';
if (last3Trimp > 270) fatigaEstado = 'alta';
else if (last3Trimp > 180) fatigaEstado = 'moderada';

const tendLoad = weeklyLoad > lastWeeklyLoad ? 'SUBIENDO' : weeklyLoad < lastWeeklyLoad ? 'BAJANDO' : 'ESTABLE';

let planContexto = 'Sin plan semanal guardado. El próximo domingo Claude generará el plan de la semana.';
if (planRow && planRow.sesiones) {
  let sesiones = planRow.sesiones;
  if (typeof sesiones === 'string') sesiones = JSON.parse(sesiones);
  const sesionActual = parseInt(planRow.sesion_actual) || 0;
  const completadas = sesiones.filter(s => s.completado).length;
  const total = sesiones.length;
  const siguiente = sesiones.find((s, i) => i >= sesionActual && !s.completado);
  const planCompletado = sesiones.every(s => s.completado);

  planContexto = `PLAN SEMANAL GENERADO POR IA (${new Date(planRow.generado_el).toLocaleDateString('es-MX')}):
${sesiones.map((s, i) => `  ${s.completado ? '✅' : i === sesionActual ? '▶️' : '⏳'} ${s.dia} — ${s.tipo}: ${s.descripcion}`).join('\n')}

Progreso: ${completadas}/${total} sesiones
${planCompletado ? 'PLAN COMPLETADO esta semana.' : siguiente ? `SIGUIENTE SESIÓN PENDIENTE → ${siguiente.dia} — ${siguiente.tipo}: ${siguiente.descripcion}` : 'Sin sesiones pendientes.'}

INSTRUCCIÓN CRÍTICA: Si preguntan qué les toca, responde EXACTAMENTE con la sesión pendiente del plan. No cambies ni improvises.`;
}

const historialTexto = historialRows.slice(0,10).map(s => {
  const f = new Date(s.fecha).toLocaleDateString('es-MX');
  return `• ${f}: ${s.distancia_km}km | ${s.pace} | ${s.zona} | TRIMP:${s.trimp} | ${s.round_like ? 'ROUNDS✓' : 'continuo'}`;
}).join('\n') || 'Sin historial.';

const contextoAtleta = `DATOS DEL ATLETA:
- Nombre: ${userName} | Edad: [EDAD] años | Altura: [ESTATURA]cm | Deporte: [DEPORTE]
- Running: 3x/semana | Total sesiones en DB: ${historialRows.length}

ESTADO ACTUAL:
- Carga semanal TRIMP: ${weeklyLoad} (tendencia: ${tendLoad})
- Km esta semana: ${kmThisWeek}km | Sesiones intensas: ${hiitThisWeek}
- Fatiga: ${fatigaEstado}
- Última sesión: ${lastSession ? `${new Date(lastSession.fecha).toLocaleDateString('es-MX')} — ${lastSession.distancia_km}km, ${lastSession.pace}, ${lastSession.zona}, TRIMP:${lastSession.trimp}` : 'Sin sesiones'}

RÉCORDS PERMANENTES:
